function jrlLookup(name) {
  // Normalize: lowercase, strip author abbreviations, keep genus + species (+ subsp. if present)
  const n = name.replace(/\xa0/g, " ").trim().toLowerCase();
  const parts = n.split(/\s+/);
  if (parts.length < 2) return null;
  // Try genus+species+subsp first, then genus+species only
  const key3 = parts[0] + " " + parts[1] + (parts[2] === "subsp." && parts[3] ? " subsp. " + parts[3] : "");
  const key2 = parts[0] + " " + parts[1];
  return JRL[key2] || JRL[key3] || null;
}



