function jrlLookup(query) {
  if (!query) return null;
  const q = query.trim();
  // 1. Exact match
  if (JRL_DATA[q]) return JRL_DATA[q];
  // 2. Case-insensitive exact
  const qLow = q.toLowerCase();
  for (const key of Object.keys(JRL_DATA)) {
    if (key.toLowerCase() === qLow) return JRL_DATA[key];
  }
  // 3. Genus+species prefix match (ignore author abbreviations)
  const parts = q.split(" ");
  if (parts.length >= 2) {
    const gs = (parts[0] + " " + parts[1]).toLowerCase();
    for (const key of Object.keys(JRL_DATA)) {
      if (key.toLowerCase().startsWith(gs)) return JRL_DATA[key];
    }
  }
  // 4. Genus-only match (return first match)
  if (parts.length >= 1) {
    const genus = parts[0].toLowerCase();
    for (const key of Object.keys(JRL_DATA)) {
      if (key.toLowerCase().startsWith(genus + " ")) return JRL_DATA[key];
    }
  }
  return null;
}

